     2	#include <tree_sitter/api.h>
     3	#include <cstring>
     4	
     5	namespace duckdb {
     6	
     7	//==============================================================================
     8	// Helper Functions Implementation
     9	//==============================================================================
    10	
    11	// Helper function to extract text from a specific child by type
    12	string ExtractChildTextByType(TSNode node, const string &content, const string &child_type) {
    13		uint32_t child_count = ts_node_child_count(node);
    14		for (uint32_t i = 0; i < child_count; i++) {
    15			TSNode child = ts_node_child(node, i);
    16			const char *current_type = ts_node_type(child);
    17	
    18			if (child_type == string(current_type)) {
    19				uint32_t start = ts_node_start_byte(child);
    20				uint32_t end = ts_node_end_byte(child);
    21				if (start < content.length() && end <= content.length()) {
    22					return content.substr(start, end - start);
    23				}
    24			}
    25		}
    26		return "";
    27	}
    28	
    29	// Helper function to extract all children of a specific type
    30	vector<TSNode> FindChildrenByType(TSNode node, const string &child_type) {
    31		vector<TSNode> children;
    32		uint32_t child_count = ts_node_child_count(node);
    33	
    34		for (uint32_t i = 0; i < child_count; i++) {
    35			TSNode child = ts_node_child(node, i);
    36			const char *current_type = ts_node_type(child);
    37	
    38			if (child_type == string(current_type)) {
    39				children.push_back(child);
    40			}
    41		}
    42	
    43		return children;
    44	}
    45	
    46	// Helper function to extract parameter list from common patterns
    47	vector<ParameterInfo> ExtractParameterList(TSNode params_node, const string &content) {
    48		vector<ParameterInfo> parameters;
    49	
    50		uint32_t child_count = ts_node_child_count(params_node);
    51		for (uint32_t i = 0; i < child_count; i++) {
    52			TSNode child = ts_node_child(params_node, i);
    53			const char *child_type = ts_node_type(child);
    54	
    55			ParameterInfo param;
    56			bool is_valid_param = false;
    57	
    58			// Handle different parameter types
    59			if (strcmp(child_type, "identifier") == 0) {
    60				// Simple parameter: def func(param):
    61				param.name = ExtractNodeText(child, content);
    62				is_valid_param = true;
    63			} else if (strcmp(child_type, "typed_parameter") == 0) {
    64				// Typed parameter: def func(param: int):
    65				param.name = ExtractChildTextByType(child, content, "identifier");
    66				param.type = ExtractChildTextByType(child, content, "type");
    67				is_valid_param = true;
    68			} else if (strcmp(child_type, "default_parameter") == 0) {
    69				// Parameter with default: def func(param=default):
    70				param.name = ExtractChildTextByType(child, content, "identifier");
    71				param.is_optional = true;
    72	
    73				// Extract default value
    74				auto default_children = FindChildrenByType(child, "=");
    75				if (!default_children.empty() && ts_node_child_count(child) > 2) {
    76					TSNode default_value = ts_node_child(child, 2); // After identifier and =
    77					param.default_value = ExtractNodeText(default_value, content);
    78				}
    79				is_valid_param = true;
    80			} else if (strcmp(child_type, "typed_default_parameter") == 0) {
    81				// Typed parameter with default: def func(param: int = default):
    82				param.name = ExtractChildTextByType(child, content, "identifier");
    83				param.type = ExtractChildTextByType(child, content, "type");
    84				param.is_optional = true;
    85	
    86				// Extract default value (typically the last child)
    87				uint32_t param_child_count = ts_node_child_count(child);
    88				if (param_child_count > 0) {
    89					TSNode last_child = ts_node_child(child, param_child_count - 1);
    90					if (strcmp(ts_node_type(last_child), "=") != 0 && strcmp(ts_node_type(last_child), "type") != 0 &&
    91					    strcmp(ts_node_type(last_child), "identifier") != 0) {
    92						param.default_value = ExtractNodeText(last_child, content);
    93					}
    94				}
    95				is_valid_param = true;
    96			} else if (strcmp(child_type, "list_splat_pattern") == 0 || strcmp(child_type, "*") == 0) {
    97				// Variadic parameter: def func(*args):
    98				param.name = ExtractChildTextByType(child, content, "identifier");
    99				if (param.name.empty()) {
   100					param.name = "*args"; // Default name
   101				} else {
   102					param.name = "*" + param.name;
   103				}
   104				param.is_variadic = true;
   105				is_valid_param = true;
   106			} else if (strcmp(child_type, "dictionary_splat_pattern") == 0 || strcmp(child_type, "**") == 0) {
   107				// Keyword variadic parameter: def func(**kwargs):
   108				param.name = ExtractChildTextByType(child, content, "identifier");
   109				if (param.name.empty()) {
   110					param.name = "**kwargs"; // Default name
   111				} else {
   112					param.name = "**" + param.name;
   113				}
   114				param.is_variadic = true;
   115				is_valid_param = true;
   116			}
