    42	string LanguageAdapter::ExtractQualifiedIdentifierName(TSNode node, const string &content) const {
    43		// Universal qualified identifier extraction
    44		// Searches for qualified/scoped identifiers and extracts just the name part
    45	
    46		// Common qualified identifier patterns across languages:
    47		// - qualified_identifier (C++): ClassName::methodName
    48		// - scoped_identifier (Java, Rust): package.ClassName.methodName
    49		// - nested_identifier (TypeScript): module.submodule.functionName
    50	
    51		vector<string> patterns = {
    52		    "qualified_identifier", "scoped_identifier", "nested_identifier",
    53		    "property_identifier" // For JS/TS object.method patterns
    54		};
    55	
    56		// First, search direct children
    57		for (const string &pattern : patterns) {
    58			TSNode qualified_node = FindChildByTypeNode(node, pattern);
    59			if (!ts_node_is_null(qualified_node)) {
    60				// Found a qualified identifier, now extract the name part
    61				return ExtractNameFromQualifiedNode(qualified_node, content);
    62			}
    63		}
    64	
    65		// If not found directly, search recursively in common containers
    66		vector<string> container_patterns = {"function_declarator", "method_declarator", "declarator", "class_body",
    67		                                     "interface_body"};
    68	
    69		for (const string &container : container_patterns) {
    70			TSNode container_node = FindChildByTypeNode(node, container);
    71			if (!ts_node_is_null(container_node)) {
    72				// Recursively search in the container
    73				string result = ExtractQualifiedIdentifierName(container_node, content);
    74				if (!result.empty()) {
    75					return result;
    76				}
    77			}
    78		}
    79	
    80		// Fallback: try regular identifier
    81		return FindChildByType(node, content, "identifier");
    82	}
