   208	string LanguageAdapter::ExtractFunctionNameFromText(TSNode node, const string &content) const {
   209		// Text-based extraction for malformed AST structures
   210		// Handles cases where tree-sitter parsing fails but we can extract from raw text
   211	
   212		string node_text = ExtractNodeText(node, content);
   213		if (node_text.empty()) {
   214			return "";
   215		}
   216	
   217		// Look for function name patterns in C/C++ style:
   218		// ReturnType ClassName::FunctionName(parameters) {
   219		// ReturnType FunctionName(parameters) const {
   220	
   221		// Find the position of the opening parenthesis
   222		size_t paren_pos = node_text.find('(');
   223		if (paren_pos == string::npos) {
   224			return ""; // Not a function signature
   225		}
   226	
   227		// Extract everything before the parenthesis
   228		string before_paren = node_text.substr(0, paren_pos);
   229	
   230		// Trim whitespace from the end
   231		while (!before_paren.empty() && isspace(before_paren.back())) {
   232			before_paren.pop_back();
   233		}
   234	
   235		if (before_paren.empty()) {
   236			return "";
   237		}
   238	
   239		// Find the last identifier before the parenthesis
   240		// This handles patterns like:
   241		// - "ReturnType FunctionName" -> "FunctionName"
   242		// - "ReturnType ClassName::FunctionName" -> "FunctionName"
   243		// - "const ReturnType& ClassName::FunctionName" -> "FunctionName"
   244	
   245		size_t last_space = before_paren.find_last_of(" \t");
   246		size_t last_colon = before_paren.find_last_of(':');
   247	
   248		// Find the start position of the function name
   249		size_t start_pos = 0;
   250		if (last_colon != string::npos && last_colon > last_space) {
   251			// Case: ClassName::FunctionName
   252			start_pos = last_colon + 1;
   253		} else if (last_space != string::npos) {
   254			// Case: ReturnType FunctionName
   255			start_pos = last_space + 1;
   256		}
   257	
   258		// Extract the function name
   259		string function_name = before_paren.substr(start_pos);
   260	
   261		// Trim any remaining whitespace
   262		while (!function_name.empty() && isspace(function_name.front())) {
   263			function_name.erase(0, 1);
   264		}
   265		while (!function_name.empty() && isspace(function_name.back())) {
   266			function_name.pop_back();
   267		}
   268	
   269		// Validate that this looks like a valid identifier
   270		if (function_name.empty() || (!isalpha(function_name[0]) && function_name[0] != '_' && function_name[0] != '~')) {
   271			return "";
   272		}
   273	
   274		return function_name;
   275	}
