   277	string LanguageAdapter::FindIdentifierInChildren(TSNode node, const string &content) const {
   278		// Try common identifier node types across languages
   279		string result = FindChildByType(node, content, "identifier");
   280		if (result.empty()) {
   281			result = FindChildByType(node, content, "property_identifier"); // JS methods
   282		}
   283		if (result.empty()) {
   284			result = FindChildByType(node, content, "field_identifier"); // Go methods
   285		}
   286		if (result.empty()) {
   287			result = FindChildByType(node, content, "qualified_identifier"); // C++
   288		}
   289		if (result.empty()) {
   290			result = FindChildByType(node, content, "name"); // PHP
   291		}
   292		if (result.empty()) {
   293			result = FindChildByType(node, content, "simple_identifier"); // Swift, Kotlin
   294		}
   295		if (result.empty()) {
   296			result = FindChildByType(node, content, "type_identifier"); // Swift types
   297		}
   298		if (result.empty()) {
   299			result = FindChildByType(node, content, "operator"); // Ruby operator methods (def +, def <<, etc.)
   300		}
   301		if (result.empty()) {
   302			result = FindChildByType(node, content, "constant"); // Ruby uppercase method names (def F, def M, etc.)
   303		}
   304		if (result.empty()) {
   305			result = FindChildByType(node, content, "setter"); // Ruby setter methods (def name=)
   306		}
   307		if (result.empty()) {
   308			result = FindChildByType(node, content, "variable_name"); // Bash vars, PHP params/properties
   309		}
   310		if (result.empty()) {
   311			result = FindChildByType(node, content, "word"); // Bash function names
   312		}
   313		return result;
   314	}
