   316	string LanguageAdapter::FindIdentifierInWrappers(TSNode node, const string &content, int depth) const {
   317		if (depth <= 0) {
   318			return "";
   319		}
   320	
   321		// Known intermediate wrapper types that may contain identifiers at a deeper level.
   322		// NOTE: "expression" is intentionally generic — it's currently only reached via HCL's
   323		// object_elem pattern (object_elem -> expression -> variable_expr -> identifier).
   324		// The depth limit and identifier-type filter constrain what gets matched, but if
   325		// false positives appear in other languages, consider qualifying it further.
   326		static const vector<string> wrapper_types = {
   327		    "variable_declarator",              // JS, C#, TypeScript
   328		    "variable_list",                    // Lua (inside assignment_statement)
   329		    "assignment_statement",             // Lua (inside variable_declaration)
   330		    "init_declarator",                  // C++
   331		    "initialized_variable_definition",  // Dart (inside local_variable_declaration)
   332		    "expression",                       // HCL (object_elem key expressions)
   333		    "variable_expr",                    // HCL (inside expression)
   334		    "constructor_param",                // Dart (inside formal_parameter for this.x)
   335		    "simple_formal_parameter",          // Dart (inside formal_parameter)
   336		    "label",                            // Dart (record_field named labels)
   337		    "constructor_signature",            // Dart (inside declaration)
   338		    "constant_constructor_signature",   // Dart (inside declaration)
   339		    "getter_signature",                 // Dart (inside declaration)
   340		    "setter_signature",                 // Dart (inside declaration)
   341		    "function_signature",               // Dart (inside declaration)
   342		    "operator_signature",               // Dart (inside declaration)
   343		};
   344	
   345		uint32_t child_count = ts_node_child_count(node);
   346		for (uint32_t i = 0; i < child_count; i++) {
   347			TSNode child = ts_node_child(node, i);
   348			const char *child_type = ts_node_type(child);
   349	
   350			for (const string &wrapper : wrapper_types) {
   351				if (wrapper == child_type) {
   352					// Found a wrapper — search for identifier types in its children
   353					string result = FindIdentifierInChildren(child, content);
   354					if (!result.empty()) {
   355						return result;
   356					}
   357					// Recurse into the wrapper's children looking for more wrappers
   358					if (depth > 1) {
   359						result = FindIdentifierInWrappers(child, content, depth - 1);
   360						if (!result.empty()) {
   361							return result;
   362						}
   363					}
   364					break; // Only match one wrapper type per child node
   365				}
   366			}
   367		}
   368		return "";
   369	}
