   382			}
   383			return "";
   384		}
   385		case ExtractionStrategy::FIND_IDENTIFIER: {
   386			string result = FindIdentifierInChildren(node, content);
   387			if (result.empty()) {
   388				result = FindIdentifierInWrappers(node, content, 2);
   389			}
   390			return result;
   391		}
   392		case ExtractionStrategy::FIND_PROPERTY:
   393			return FindChildByType(node, content, "property_identifier");
   394		case ExtractionStrategy::FIND_QUALIFIED_IDENTIFIER:
   395			return ExtractQualifiedIdentifierName(node, content);
   396		case ExtractionStrategy::FIND_IN_DECLARATOR:
   397			return ExtractNameFromDeclarator(node, content);
   398		case ExtractionStrategy::FIND_ASSIGNMENT_TARGET: {
   399			// Universal pattern: find identifier in parent assignment
   400			// Handles: R (name <- func), JS (const name = func), C++ (auto name = lambda), Python (x = lambda), etc.
   401			TSNode parent = ts_node_parent(node);
   402			if (!ts_node_is_null(parent)) {
   403				string parent_type = ts_node_type(parent);
   404				// Check for assignment patterns across languages
   405				if (parent_type == "binary_operator" ||               // R: name <- function
   406				    parent_type == "variable_declarator" ||           // JS/TS: const name = function
   407				    parent_type == "init_declarator" ||               // C++: auto name = lambda
   408				    parent_type == "assignment" ||                    // Python: x = lambda
   409				    parent_type == "named_expression" ||              // Python: (x := lambda)
   410				    parent_type == "initialized_variable_definition" || // Dart: var name = () => ...
   411				    parent_type.find("declarator") != string::npos) { // Other declarator patterns
   412	
   413					// Find identifier among parent's children
   414					// In most languages (JS, Python, C++) the identifier is the first child,
   415					// but in Dart initialized_variable_definition the type annotation comes first
   416					return FindChildByType(parent, content, "identifier");
   417				}
   418			}
   419			return "";
   420		}
   421		case ExtractionStrategy::FIND_CALL_TARGET: {
   422			// Extract method/function name from call expressions
   423			// Handles: simple calls (print), method calls (obj.method), qualified calls (pkg.func)
   424			if (ts_node_child_count(node) == 0) {
   425				return "";
   426			}
   427	
   428			TSNode first_child = ts_node_child(node, 0);
   429			if (ts_node_is_null(first_child)) {
   430				return "";
   431			}
   432	
   433			string first_child_type = ts_node_type(first_child);
   434	
   435			// Simple function call: first child is identifier
   436			// But in Java method_invocation, the first identifier is the object, not the method.
   437			// Check if there's a later identifier sibling (before argument_list) which would be the method name.
   438			if (first_child_type == "identifier") {
   439				uint32_t node_child_count = ts_node_child_count(node);
   440				for (uint32_t i = 1; i < node_child_count; i++) {
   441					TSNode sibling = ts_node_child(node, i);
   442					string sibling_type = ts_node_type(sibling);
   443					// Stop at argument containers
   444					if (sibling_type == "argument_list" || sibling_type == "arguments") {
   445						break;
   446					}
   447					if (sibling_type == "identifier" || sibling_type == "property_identifier" ||
   448					    sibling_type == "field_identifier" || sibling_type == "simple_identifier") {
   449						return ExtractNodeText(sibling, content);
   450					}
   451				}
   452				// No later identifier found — this IS the function name (Python, etc.)
   453				return ExtractNodeText(first_child, content);
   454			}
   455	
   456			// Method/member call patterns: find the rightmost identifier (method name)
   457			// Python: attribute (obj.method), JS/TS: member_expression, C++: field_expression
   458			// Go: selector_expression, Rust: field_expression, Java: field_access
   459			if (first_child_type == "attribute" || first_child_type == "member_expression" ||
   460			    first_child_type == "field_expression" || first_child_type == "selector_expression" ||
   461			    first_child_type == "field_access" || first_child_type == "scoped_identifier" ||
   462			    first_child_type == "qualified_identifier") {
   463	
   464				// Java method_invocation has a special structure: the method name is a sibling
   465				// of field_access, not inside it. E.g., System.out.println():
   466				//   method_invocation -> field_access("System.out"), ".", identifier("println"), argument_list
   467				// Check for an identifier sibling after the first child (the object expression)
   468				uint32_t node_child_count = ts_node_child_count(node);
   469				for (uint32_t i = 1; i < node_child_count; i++) {
   470					TSNode sibling = ts_node_child(node, i);
   471					string sibling_type = ts_node_type(sibling);
   472					if (sibling_type == "identifier" || sibling_type == "property_identifier" ||
   473					    sibling_type == "field_identifier" || sibling_type == "simple_identifier") {
   474						return ExtractNodeText(sibling, content);
   475					}
   476				}
   477	
   478				// Fallback: find the last identifier inside the first child
   479				// (Python attribute, JS member_expression, etc.)
   480				uint32_t child_count = ts_node_child_count(first_child);
   481				for (int i = child_count - 1; i >= 0; i--) {
   482					TSNode child = ts_node_child(first_child, i);
   483					string child_type = ts_node_type(child);
   484	
   485					if (child_type == "identifier" || child_type == "property_identifier" ||
   486					    child_type == "field_identifier" || child_type == "simple_identifier") {
   487						return ExtractNodeText(child, content);
   488					}
   489				}
   490	
   491				// Fallback: return the full expression text
   492				return ExtractNodeText(first_child, content);
   493			}
   494	
   495			// Other patterns (subscript calls, etc.): try to find any identifier
   496			return FindChildByType(node, content, "identifier");
   497		}
   498		case ExtractionStrategy::CUSTOM:
   499			// Will be overridden by specific language adapters
   500			return "";
   501		default:
   502			return "";
   503		}
   504	}
