   655			// For tree-sitter based adapters, test parser creation
   656			auto test_adapter = const_cast<LanguageAdapter *>(adapter);
   657			TSParser *parser = test_adapter->GetParser();
   658			if (!parser) {
   659				throw InvalidInputException("Language adapter for '" + language + "' failed to create parser");
   660			}
   661		} catch (const Exception &e) {
   662			throw InvalidInputException("Language adapter for '" + adapter->GetLanguageName() +
   663			                            "' failed validation: " + e.what());
