   125	string LanguageAdapter::ExtractNameFromDeclarator(TSNode node, const string &content) const {
   126		// Universal declarator extraction
   127		// Searches for identifiers inside declarator nodes
   128	
   129		// Common declarator patterns across languages:
   130		// - function_declarator (C/C++): contains function name and parameters
   131		// - method_declarator (Java): contains method name and parameters
   132		// - declarator (various): general declaration pattern
   133	
   134		vector<string> declarator_patterns = {
   135		    "function_declarator", "method_declarator", "declarator",
   136		    "procedure_declarator", // Pascal-like languages
   137		    "init_declarator",      // C++ initializing declarators
   138		    "variable_declarator"   // Java field/variable declarations
   139		};
   140	
   141		// Wrapper types that may contain the actual declarator (e.g., for pointer/array return types)
   142		vector<string> wrapper_patterns = {
   143		    "pointer_declarator",  // char *func() - function_declarator is inside pointer_declarator
   144		    "array_declarator",    // int arr[]() - function_declarator is inside array_declarator
   145		    "reference_declarator" // C++ references
   146		};
   147	
   148		// Helper lambda to search for declarator and extract name
   149		auto tryExtractFromDeclarator = [&](TSNode search_node) -> string {
   150			for (const string &pattern : declarator_patterns) {
   151				TSNode declarator_node = FindChildByTypeNode(search_node, pattern);
   152				if (!ts_node_is_null(declarator_node)) {
   153					// Found a declarator, extract identifier from it
   154					// First try qualified identifier (for method names like Class::method)
   155					string result = ExtractQualifiedIdentifierName(declarator_node, content);
   156					if (!result.empty()) {
   157						return result;
   158					}
   159	
   160					// Fallback to simple identifier
   161					result = FindChildByType(declarator_node, content, "identifier");
   162					if (!result.empty()) {
   163						return result;
   164					}
   165				}
   166			}
   167			return "";
   168		};
   169	
   170		// First, try to find declarator directly under node
   171		string result = tryExtractFromDeclarator(node);
   172		if (!result.empty()) {
   173			return result;
   174		}
   175	
   176		// If not found, check inside wrapper types (pointer_declarator, array_declarator)
