   260	
   261		// Trim any remaining whitespace
   262		while (!function_name.empty() && isspace(function_name.front())) {
   263			function_name.erase(0, 1);
   264		}
   265		while (!function_name.empty() && isspace(function_name.back())) {
   266			function_name.pop_back();
   267		}
   268	
   269		// Validate that this looks like a valid identifier
   270		if (function_name.empty() || (!isalpha(function_name[0]) && function_name[0] != '_' && function_name[0] != '~')) {
   271			return "";
   272		}
   273	
   274		return function_name;
   275	}
