   639	void LanguageAdapterRegistry::ValidateLanguageABI(const LanguageAdapter *adapter) const {
   640		// Test adapter functionality to validate ABI compatibility
   641		try {
   642			string language = adapter->GetLanguageName();
   643	
   644			// For DuckDB adapter, test that parsing function can be retrieved
   645			if (language == "duckdb") {
   646				// Test that the parsing function is available without calling it
   647				ParsingFunction parsing_fn = adapter->GetParsingFunction();
   648				if (!parsing_fn) {
   649					throw InvalidInputException("DuckDB adapter failed to provide parsing function");
   650				}
   651				// Parsing function exists - validation successful
   652				return;
   653			}
   654	
   655			// For tree-sitter based adapters, test parser creation
   656			auto test_adapter = const_cast<LanguageAdapter *>(adapter);
   657			TSParser *parser = test_adapter->GetParser();
   658			if (!parser) {
   659				throw InvalidInputException("Language adapter for '" + language + "' failed to create parser");
   660			}
   661		} catch (const Exception &e) {
   662			throw InvalidInputException("Language adapter for '" + adapter->GetLanguageName() +
   663			                            "' failed validation: " + e.what());
   664		}
   665	}
