 19	string LanguageAdapter::ExtractNodeText(TSNode node, const string &content) const {
 20		uint32_t start_byte = ts_node_start_byte(node);
 21		uint32_t end_byte = ts_node_end_byte(node);
 22	
 23		if (start_byte >= content.size() || end_byte > content.size() || start_byte >= end_byte) {
 24			return "";
