 30	string LanguageAdapter::FindChildByType(TSNode node, const string &content, const string &child_type) const {
 31		uint32_t child_count = ts_node_child_count(node);
 32		for (uint32_t i = 0; i < child_count; i++) {
 33			TSNode child = ts_node_child(node, i);
 34			const char *type = ts_node_type(child);
 35			if (child_type == type) {
 36				return ExtractNodeText(child, content);
