 84	TSNode LanguageAdapter::FindChildByTypeNode(TSNode node, const string &child_type) const {
 85		uint32_t child_count = ts_node_child_count(node);
 86		for (uint32_t i = 0; i < child_count; i++) {
 87			TSNode child = ts_node_child(node, i);
 88			const char *type = ts_node_type(child);
 89			if (child_type == type) {
 90				return child;
