 96	string LanguageAdapter::ExtractNameFromQualifiedNode(TSNode qualified_node, const string &content) const {
 97		// Extract the final identifier from qualified names like:
 98		// - ClassName::methodName -> methodName
 99		// - package.Class.method -> method
100		// - module.submodule.func -> func
101	
102		uint32_t child_count = ts_node_child_count(qualified_node);
103	
104		// Look for the last identifier in the qualified chain
105		string last_identifier = "";
106		for (uint32_t i = 0; i < child_count; i++) {
107			TSNode child = ts_node_child(qualified_node, i);
108			const char *child_type = ts_node_type(child);
109	
110			if (strcmp(child_type, "identifier") == 0) {
111				// Keep track of the last identifier found
112				last_identifier = ExtractNodeText(child, content);
113			}
114		}
115	
116		// If we found an identifier, return it; otherwise return the full qualified name
117		if (!last_identifier.empty()) {
118			return last_identifier;
119		}
120	
121		// Fallback: return the entire qualified identifier text
122		return ExtractNodeText(qualified_node, content);
123	}
