553	const LanguageAdapter *LanguageAdapterRegistry::GetAdapter(const string &language) const {
554		// MEMORY SAFETY FIX: Eliminate persistent adapter caching to prevent state accumulation
555		// This function now creates fresh adapters for each call to prevent the segfault
556		// caused by cumulative adapter state across multiple parsing operations
557	
558		// WARNING: This method should be deprecated in favor of CreateAdapter()
559		// for proper memory management. Using pre_created_adapters is preferred.
560	
561		lock_guard<mutex> lock(registry_mutex_);
562	
563		// Resolve alias to actual language name
564		string actual_language = language;
565		auto alias_it = alias_to_language.find(language);
566		if (alias_it != alias_to_language.end()) {
567			actual_language = alias_it->second;
568		}
569	
570		// Check if we have a factory for this language
571		auto factory_it = language_factories.find(actual_language);
572		if (factory_it != language_factories.end()) {
573			// Create a fresh adapter instance - NO PERSISTENT CACHING
574			auto adapter = factory_it->second();
575	
576			// Validate ABI compatibility
577			ValidateLanguageABI(adapter.get());
578	
579			// TEMPORARY: Store adapter in mutable map but clear it periodically to prevent accumulation
580			// This is not ideal but maintains API compatibility while fixing the segfault
581			auto *adapter_ptr = adapter.get();
582	
583			// Clear old entries periodically to prevent unbounded growth
584			if (adapters.size() > 10) {
585				adapters.clear();
586			}
587	
588			adapters[actual_language] = std::move(adapter);
589			return adapter_ptr;
590		}
591	
592		return nullptr;
