   198						// Function keywords
   199						uint32_t start = ts_node_start_byte(sibling);
   200						uint32_t end = ts_node_end_byte(sibling);
   201						if (start < content.length() && end <= content.length()) {
   202							modifiers.push_back(content.substr(start, end - start));
   203						}
   204					}
   205				}
   206			}
   207	
   208			return modifiers;
   209		}
   210	};
