   216			// Reuse FUNCTION_WITH_PARAMS logic and add async modifier
   217			auto context = RustNativeExtractor<NativeExtractionStrategy::FUNCTION_WITH_PARAMS>::Extract(node, content);
   218			context.modifiers.insert(context.modifiers.begin(), "async");
   219			return context;
   220		}
   221	};
   222	
   223	// Specialization for CLASS_WITH_METHODS (Rust structs/enums with impl blocks)
   224	template <>
   225	struct RustNativeExtractor<NativeExtractionStrategy::CLASS_WITH_METHODS> {
   226		static NativeContext Extract(TSNode node, const string &content) {
   227			NativeContext context;
   228	
   229			// Determine if this is a struct, enum, or trait
   230			const char *node_type = ts_node_type(node);
   231			if (strcmp(node_type, "struct_item") == 0) {
   232				context.signature_type = "struct";
   233			} else if (strcmp(node_type, "enum_item") == 0) {
   234				context.signature_type = "enum";
   235			} else if (strcmp(node_type, "trait_item") == 0) {
   236				context.signature_type = "trait";
   237			} else if (strcmp(node_type, "impl_item") == 0) {
   238				context.signature_type = "impl";
   239			} else {
   240				context.signature_type = "type";
   241			}
