   251		static vector<string> ExtractRustTypeModifiers(TSNode node, const string &content) {
   252			vector<string> modifiers;
   253	
   254			uint32_t child_count = ts_node_child_count(node);
   255			for (uint32_t i = 0; i < child_count; i++) {
   256				TSNode child = ts_node_child(node, i);
   257				const char *child_type = ts_node_type(child);
   258	
   259				if (strcmp(child_type, "visibility_modifier") == 0) {
   260					// pub visibility
   261					uint32_t start = ts_node_start_byte(child);
   262					uint32_t end = ts_node_end_byte(child);
   263					if (start < content.length() && end <= content.length()) {
   264						modifiers.push_back(content.substr(start, end - start));
   265					}
   266				} else if (strcmp(child_type, "attribute_item") == 0) {
   267					// #[derive(...)] and other attributes
   268					uint32_t start = ts_node_start_byte(child);
   269					uint32_t end = ts_node_end_byte(child);
   270					if (start < content.length() && end <= content.length()) {
   271						modifiers.push_back(content.substr(start, end - start));
   272					}
   273				} else if (strcmp(child_type, "type_parameters") == 0) {
   274					// Generic parameters <T, U>
   275					uint32_t start = ts_node_start_byte(child);
   276					uint32_t end = ts_node_end_byte(child);
   277					if (start < content.length() && end <= content.length()) {
   278						modifiers.push_back("generic" + content.substr(start, end - start));
   279					}
